(function executeRule(current, previous /*null when async*/) {
  if (current.category == 'inquiry' && current.assignment_group.nil()) {
    current.assignment_group = '287ebd7da9fe198100f92cc8d1d2154e';
  }
})(current, previous);

(function executeRule(current, previous /*null when async*/) {
  if (!current.serial_number.nil()) {
    var ci = new GlideRecord('cmdb_ci_server');
    ci.addQuery('serial_number', current.serial_number);
    ci.query();
    if (ci.next()) {
      gs.addErrorMessage('A server CI with this serial number already exists: ' + ci.getDisplayValue('name'));
      current.setAbortAction(true);
    }
  }
})(current, previous);

(function executeRule(current, previous /*null when async*/) {
  current.orderByDesc('sys_created_on');
})(current, previous);
